        foreach ($a in $excess) { $null = $flaggedNames.Add($a.Name) }
    }

    $toDelete = $Artifacts | Where-Object { $flaggedNames.Contains($_.Name) }
    $toRetain = $Artifacts | Where-Object { -not $flaggedNames.Contains($_.Name) }

